using Microsoft.AspNetCore.Mvc;\n\nnamespace ApexCustomClothiers.Controllers\n{\n    [ApiController]\n    [Route("[controller]")]\n    public class AboutController : ControllerBase\n    {\n        [HttpGet]\n        public IActionResult GetAboutInfo()\n        {\n            var aboutInfo = new\n            {\n                Mission = "To provide the highest quality custom clothing while ensuring sustainability and style.",\n                Vision = "To be the leading brand in custom clothing that merges sustainability with fashion.",\n                TeamMembers = new[] \n                {\n                    "Alice Johnson - Founder\",\n                    "Bob Smith - Head Designer\",\n                    "Charlie Davis - Marketing Specialist\"\n                }\n            };\n            return Ok(aboutInfo);\n        }\n    }\n}